#if UNITY_EDITOR
using System;
using System.Collections.Generic;
using System.Linq;
using System.Reflection;
using System.Text.RegularExpressions;
using UnityEditor;
using UnityEngine;

/// <summary>
/// Utilitário partilhado para desenhar listas polimórficas [SerializeReference]
/// (ex: List&lt;NpcCondition&gt;, List&lt;NpcAction&gt;), com um botão
/// "+ Adicionar..." que lista, via reflexão, todas as subclasses concretas do
/// tipo base encontradas no projecto — incluindo novas que sejam adicionadas no
/// futuro, sem precisar de tocar em nenhum editor.
///
/// Usado por NpcControllerEditor (Condições/Ações dos eventos, Condições de
/// Visibilidade) e MusicZoneEditor (Condições da zona, Etapa 8).
/// </summary>
public static class PolymorphicListDrawer
{
    private static readonly Dictionary<Type, List<Type>> _subtypeCache = new Dictionary<Type, List<Type>>();

    /// <summary>Devolve (e põe em cache) todas as subclasses concretas e não-genéricas de "baseType".</summary>
    public static List<Type> GetSubtypes(Type baseType)
    {
        if (!_subtypeCache.TryGetValue(baseType, out var list))
        {
            list = FindSubtypes(baseType);
            _subtypeCache[baseType] = list;
        }

        return list;
    }

    /// <summary>
    /// Desenha "listProp" (List&lt;baseType&gt; marcada com [SerializeReference])
    /// com um foldout "helpbox" por elemento, botão "X" para remover, e um
    /// botão "+ addLabel" que mostra um menu com todas as subclasses concretas
    /// de "baseType" para adicionar uma nova.
    /// </summary>
    public static void Draw(SerializedObject serializedObject, SerializedProperty listProp, string title, Type baseType, string addLabel)
    {
        var types = GetSubtypes(baseType);

        EditorGUILayout.LabelField(title, EditorStyles.boldLabel);

        int removeIndex = -1;

        for (int i = 0; i < listProp.arraySize; i++)
        {
            var element = listProp.GetArrayElementAtIndex(i);

            EditorGUILayout.BeginVertical("helpbox");
            EditorGUILayout.BeginHorizontal();

            EditorGUILayout.LabelField(GetManagedTypeDisplayName(element), EditorStyles.miniBoldLabel);

            GUILayout.FlexibleSpace();
            if (GUILayout.Button("X", GUILayout.Width(22)))
                removeIndex = i;

            EditorGUILayout.EndHorizontal();

            if (removeIndex != i)
            {
                EditorGUI.indentLevel++;
                DrawChildProperties(element);
                EditorGUI.indentLevel--;
            }

            EditorGUILayout.EndVertical();
        }

        if (removeIndex >= 0)
            listProp.DeleteArrayElementAtIndex(removeIndex);

        if (GUILayout.Button($"+ {addLabel}"))
            ShowAddTypeMenu(serializedObject, listProp.propertyPath, types);

        EditorGUILayout.Space();
    }

    private static void ShowAddTypeMenu(SerializedObject serializedObject, string listPropertyPath, List<Type> types)
    {
        var menu = new GenericMenu();

        if (types.Count == 0)
        {
            menu.AddDisabledItem(new GUIContent("(nenhum tipo encontrado)"));
        }
        else
        {
            foreach (var type in types)
            {
                var capturedType = type;
                menu.AddItem(new GUIContent(GetTypeMenuName(capturedType)), false, () => AddElement(serializedObject, listPropertyPath, capturedType));
            }
        }

        menu.ShowAsContext();
    }

    private static void AddElement(SerializedObject serializedObject, string listPropertyPath, Type type)
    {
        serializedObject.Update();

        var listProp = serializedObject.FindProperty(listPropertyPath);

        int newIndex = listProp.arraySize;
        listProp.arraySize++;

        var element = listProp.GetArrayElementAtIndex(newIndex);
        element.managedReferenceValue = Activator.CreateInstance(type);

        serializedObject.ApplyModifiedProperties();
    }

    /// <summary>
    /// Tipos-base conhecidos para listas [SerializeReference] ANINHADAS dentro de
    /// um elemento (ex: Action_ConditionalBranch.conditions — Etapa 5.3). Estas
    /// listas são desenhadas recursivamente com o mesmo "+ Adicionar...".
    /// </summary>
    private static readonly Dictionary<string, Type> _nestedListBaseTypes = new Dictionary<string, Type>
    {
        { "NpcCondition", typeof(NpcCondition) },
        { "NpcAction", typeof(NpcAction) },
        { "EnemyCondition", typeof(EnemyCondition) },
        { "EnemyAttack", typeof(EnemyAttack) },
    };

    /// <summary>Desenha todos os campos visíveis de um elemento [SerializeReference] (sem o cabeçalho/tipo). Listas [SerializeReference] aninhadas de tipos conhecidos são desenhadas recursivamente via Draw.</summary>
    private static void DrawChildProperties(SerializedProperty property)
    {
        var endProperty = property.GetEndProperty();
        var iterator = property.Copy();

        bool enterChildren = true;
        while (iterator.NextVisible(enterChildren) && !SerializedProperty.EqualContents(iterator, endProperty))
        {
            enterChildren = false;

            // Lista [SerializeReference] aninhada (ex: condições de um branch):
            // arrayElementType vem como "managedReference<NpcCondition>".
            if (iterator.isArray && iterator.arrayElementType != null && iterator.arrayElementType.StartsWith("managedReference"))
            {
                string inner = ExtractInnerTypeName(iterator.arrayElementType);

                if (inner != null && _nestedListBaseTypes.TryGetValue(inner, out var baseType))
                {
                    Draw(property.serializedObject, iterator.Copy(), iterator.displayName, baseType, $"Adicionar {iterator.displayName}");
                    continue;
                }
            }

            EditorGUILayout.PropertyField(iterator, true);
        }
    }

    /// <summary>Extrai "NpcCondition" de "managedReference&lt;NpcCondition&gt;" (devolve null se não tiver o formato esperado).</summary>
    private static string ExtractInnerTypeName(string arrayElementType)
    {
        int open = arrayElementType.IndexOf('<');
        int close = arrayElementType.LastIndexOf('>');
        if (open < 0 || close <= open) return null;

        string inner = arrayElementType.Substring(open + 1, close - open - 1);
        int dot = inner.LastIndexOf('.');
        return dot >= 0 ? inner.Substring(dot + 1) : inner;
    }

    /// <summary>Encontra todas as subclasses concretas e não-genéricas de "baseType" em qualquer assembly carregada.</summary>
    private static List<Type> FindSubtypes(Type baseType)
    {
        var result = new List<Type>();

        foreach (var assembly in AppDomain.CurrentDomain.GetAssemblies())
        {
            Type[] types;

            try
            {
                types = assembly.GetTypes();
            }
            catch (ReflectionTypeLoadException e)
            {
                types = e.Types.Where(t => t != null).ToArray();
            }

            foreach (var type in types)
            {
                if (type.IsAbstract || type.IsGenericTypeDefinition) continue;
                if (baseType.IsAssignableFrom(type)) result.Add(type);
            }
        }

        result.Sort((a, b) => string.Compare(a.Name, b.Name, StringComparison.Ordinal));
        return result;
    }

    /// <summary>Nome do tipo a mostrar no item do menu "+ Adicionar...": remove o prefixo Condition_/Action_/Attack_ e separa palavras.</summary>
    private static string GetTypeMenuName(Type type)
    {
        string name = type.Name;

        if (name.StartsWith("Condition_")) name = name.Substring("Condition_".Length);
        else if (name.StartsWith("Action_")) name = name.Substring("Action_".Length);
        else if (name.StartsWith("Attack_")) name = name.Substring("Attack_".Length);
        else if (name.StartsWith("Objective_")) name = name.Substring("Objective_".Length);
        else if (name.StartsWith("FailCondition_")) name = name.Substring("FailCondition_".Length);

        return Regex.Replace(name, "(?<!^)([A-Z])", " $1");
    }

    /// <summary>Nome do tipo guardado num campo [SerializeReference], para mostrar no cabeçalho do elemento.</summary>
    private static string GetManagedTypeDisplayName(SerializedProperty property)
    {
        string fullTypeName = property.managedReferenceFullTypename;
        if (string.IsNullOrEmpty(fullTypeName)) return "(vazio)";

        int spaceIndex = fullTypeName.LastIndexOf(' ');
        string typeName = spaceIndex >= 0 ? fullTypeName.Substring(spaceIndex + 1) : fullTypeName;

        int dotIndex = typeName.LastIndexOf('.');
        if (dotIndex >= 0) typeName = typeName.Substring(dotIndex + 1);

        if (typeName.StartsWith("Condition_")) typeName = typeName.Substring("Condition_".Length);
        else if (typeName.StartsWith("Action_")) typeName = typeName.Substring("Action_".Length);
        else if (typeName.StartsWith("Objective_")) typeName = typeName.Substring("Objective_".Length);
        else if (typeName.StartsWith("FailCondition_")) typeName = typeName.Substring("FailCondition_".Length);

        return Regex.Replace(typeName, "(?<!^)([A-Z])", " $1").Trim();
    }
}
#endif
